        ))}
      </div>
    </div>
  );

  const renderStep5 = () => (
    <div className="space-y-8 animate-in zoom-in-95">
      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 space-y-8">
          <div className="w-20 h-20 border-4 border-stone-100 border-t-black rounded-full animate-spin" />
          <h3 className="text-2xl font-bold text-black font-serif">Generando arte...</h3>
        </div>
      ) : error ? (
        <div className="py-24 text-center space-y-6">
          <p className="text-red-500 font-bold">{error}</p>
          <button onClick={() => selectAndGenerate(state.selectedConceptIndex!)} className="bg-black text-white px-8 py-3 rounded-xl font-bold">Reintentar</button>
        </div>
      ) : state.imageHistory[0] ? (
        <div className="space-y-8">
          <div className="rounded-3xl overflow-hidden border border-stone-100 shadow-2xl bg-white aspect-square relative">
            <img src={state.imageHistory[0]} alt="Final" className="w-full h-full object-cover" />
          </div>
          <div className="grid grid-cols-3 gap-3">
            <button onClick={() => selectAndGenerate(state.selectedConceptIndex!)} className={btnSecondary}>Regenerar</button>
            <button onClick={() => setState(p => ({ ...p, step: 4 }))} className={btnSecondary}>Propuestas</button>
            <button onClick={() => handleDownload(state.imageHistory[0])} className="py-4 rounded-xl bg-black text-white font-bold px-4">Descargar</button>
          </div>
          <div className="pt-6 border-t border-stone-100 space-y-4">
            <h4 className="text-sm font-black text-stone-900 uppercase tracking-widest">Ajustar</h4>
