import { GoogleGenAI, Type } from "@google/genai";
import { Wine, ImageType, FunnelState } from "../types";

export const generateVisualConcepts = async (wine: Wine, state: FunnelState): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Eres un Director Creativo experto en fotografía de vinos para Kinglab Bodegas 202.
    Analiza la siguiente información y genera 3 conceptos visuales distintos, creativos y profesionales en ESPAÑOL.

    PRODUCTO:
    - Nombre: ${wine.name}
    - Perfil: ${wine.description}
    - Público: ${wine.targetAudience}
    - Nivel: ${wine.priceLevel}
    - Especial: ${wine.specialFeatures.join(', ')}

    TIPO DE IMAGEN: ${state.type}
    UBICACIÓN: ${state.location}
    DETALLES ELEGIDOS: ${JSON.stringify(state.selections)}
    CONTEXTO ADICIONAL: ${state.contextText || 'Ninguno'}

    REGLAS:
    - Los conceptos deben ser cortos (un párrafo de 30-40 palabras cada uno).
    - Lenguaje editorial, elegante y descriptivo.
    - Cada concepto debe ser único en su enfoque visual e integrar la ubicación seleccionada.
    - Idioma: Español.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            concepts: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Tres párrafos descriptivos de conceptos visuales."
            }
          },
          required: ["concepts"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return data.concepts || [];
  } catch (error) {
    console.error("Error generating concepts:", error);
    throw error;
  }
};

export const generateFinalImage = async (
  wine: Wine, 
  concept: string, 
  ratio: string, 
  adjustment?: string
): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const base64Data = wine.image.split(',')[1];
  const mimeType = wine.image.split(';')[0].split(':')[1];

  let prompt = `
    Genera una imagen publicitaria de alta calidad basada ESTRICTAMENTE en este concepto creativo:
    "${concept}"

    DETALLES TÉCNICOS:
    - Producto: ${wine.name}
    - Objetivo: Mantener la esencia de la botella de la imagen de referencia pero en un entorno publicitario profesional.
    - Estilo: Fotografía publicitaria de lujo, alta gama, iluminación cinematográfica.
  `;

  if (adjustment) {
    prompt += `\n\nAJUSTE ESPECÍFICO APLICAR: "${adjustment}".`;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType } },
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: ratio as any
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating final image:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio, GalleryImage } from '../types';
import { generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
  initialData?: {
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  };
}

const LOCATIONS = ["Bodega / Cava", "Viñedo", "Mesa de Hogar", "Restaurante", "Wine Bar", "Entorno Minimalista"];

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery, initialData }) => {
  const [selectedWine, setSelectedWine] = useState<Wine>(initialData?.wine || wines[0]);
  const [state, setState] = useState<FunnelState>({
    type: null,
    location: null,
    step: initialData ? 6 : 1,
    selections: {},
    contextText: '',
    concepts: initialData ? [initialData.concept] : [],
    selectedConceptIndex: initialData ? 0 : null,
    editingConceptIndex: null,
    imageHistory: []
  });
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');

  useEffect(() => {
    if (initialData && state.step === 6 && state.imageHistory.length === 0) {
      if (!initialData.isAdjustment) {
        selectAndGenerate(0);
      }
    }
  }, []);

  const handleSelection = (key: string, value: string) => {
    setState(prev => ({ ...prev, selections: { ...prev.selections, [key]: value } }));
  };

  const nextStep = () => {
    setError(null);
    setState(prev => ({ ...prev, step: prev.step + 1 }));
  };

  const prevStep = () => {
    setError(null);
    setState(prev => ({ ...prev, step: Math.max(1, prev.step - 1) }));
  };

  const startConceptGeneration = async () => {
    setLoading(true);
    setError(null);
    setState(prev => ({ ...prev, concepts: [], selectedConceptIndex: null, imageHistory: [] }));

    try {
      const concepts = await generateVisualConcepts(selectedWine, state);
      if (concepts && concepts.length > 0) {
        setState(prev => ({ ...prev, concepts, step: 5 }));
      } else {
        throw new Error("No concepts returned");
      }
    } catch (e) {
      setError("No se pudieron generar conceptos creativos. Reintenta.");
    } finally {
      setLoading(false);
    }
  };

  const selectAndGenerate = async (index: number, adjustment?: string) => {
    setLoading(true);
    setError(null);
    setState(prev => ({ ...prev, selectedConceptIndex: index, step: 6 }));

    try {
      const img = await generateFinalImage(selectedWine, state.concepts[index], ratio, adjustment);
      if (img) {
        const galleryItem: GalleryImage = {
          id: Date.now().toString(),
          url: img,
          concept: state.concepts[index],
          wineName: selectedWine.name,
          timestamp: Date.now()
        };
        onSaveToGallery(galleryItem);
        setState(prev => ({ ...prev, imageHistory: [img] }));
      } else {
        throw new Error("Empty image result");
      }
    } catch (e) {
      setError("Error durante la generación de la imagen.");
    } finally {
      setLoading(false);
    }
  };

  const handleAdjustment = (adjustment: string) => {
    if (state.selectedConceptIndex !== null) {
      selectAndGenerate(state.selectedConceptIndex, adjustment);
    }
  };

  const handleSaveEdit = () => {
    if (state.editingConceptIndex !== null) {
      const newConcepts = [...state.concepts];
      newConcepts[state.editingConceptIndex] = editValue;
      setState(prev => ({ ...prev, concepts: newConcepts, editingConceptIndex: null }));
    }
  };

  const handleDownload = (imgUrl: string) => {
    const link = document.createElement('a');
    link.href = imgUrl;
    link.download = `kinglab_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const btnSecondary = "py-4 rounded-xl border border-stone-300 bg-white text-stone-900 font-bold hover:border-black active:bg-stone-50 transition-all text-center px-4";
  const btnPrimary = "w-full py-5 bg-black text-white rounded-2xl font-bold shadow-xl shadow-black/10 active:scale-95 transition-all text-lg flex items-center justify-center gap-3";
  const stepIndicator = (current: number) => (
    <div className="flex justify-center gap-2 mb-8">
      {[1, 2, 3, 4, 5].map(i => (
        <div key={i} className={`h-1 rounded-full transition-all ${i === current ? 'w-8 bg-black' : 'w-2 bg-stone-200'}`} />
      ))}
    </div>
  );

  // Step 1: PRODUCT
  const renderStep1 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      {stepIndicator(1)}
      <div className="space-y-6">
        <h2 className="text-3xl font-bold text-black font-serif">1. Selecciona el Producto</h2>
        <div className="grid gap-4">
          {wines.map(w => (
            <button 
              key={w.id} 
              onClick={() => { setSelectedWine(w); nextStep(); }}
              className={`w-full py-6 rounded-2xl border-2 text-left px-8 hover:border-black transition-all shadow-sm flex items-center gap-6 group ${selectedWine.id === w.id ? 'border-black bg-stone-50' : 'border-stone-100 bg-white'}`}
            >
              <img src={w.image} className="w-16 h-16 object-contain" />
              <div className="flex-1">
                <p className="text-lg font-bold">{w.name}</p>
                <p className="text-stone-400 text-sm">{w.description.substring(0, 40)}...</p>
              </div>
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="opacity-40 group-hover:opacity-100 transition-opacity"><path d="m9 18 6-6-6-6"/></svg>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  // Step 2: IMAGE TYPE
  const renderStep2 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      {stepIndicator(2)}
      <div className="space-y-6">
        <h2 className="text-3xl font-bold text-black font-serif">2. Tipo de Imagen</h2>
        <div className="grid gap-3">
          {Object.values(ImageType).map(t => (
            <button key={t} onClick={() => { setState(prev => ({ ...prev, type: t })); nextStep(); }} className={`w-full py-6 rounded-2xl border-2 bg-white text-stone-900 font-bold text-left px-8 hover:border-black transition-all shadow-sm active:bg-stone-50 flex justify-between items-center group ${state.type === t ? 'border-black' : 'border-stone-100'}`}>
              {t}
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="opacity-0 group-hover:opacity-100 transition-opacity"><path d="m9 18 6-6-6-6"/></svg>
            </button>
          ))}
        </div>
        <button onClick={prevStep} className="w-full text-stone-400 font-bold py-2">Volver al producto</button>
      </div>
    </div>
  );

  // Step 3: WHERE (LOCATION)
  const renderStep3 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      {stepIndicator(3)}
      <div className="space-y-6">
        <h2 className="text-3xl font-bold text-black font-serif">3. ¿Dónde ocurre?</h2>
        <p className="text-stone-500 font-medium">Define el entorno físico de la fotografía.</p>
        <div className="grid grid-cols-2 gap-3">
          {LOCATIONS.map(loc => (
            <button 
              key={loc} 
              onClick={() => { setState(prev => ({ ...prev, location: loc })); nextStep(); }} 
              className={`py-6 rounded-2xl border-2 font-bold transition-all px-4 text-center ${state.location === loc ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100 hover:border-stone-300'}`}
            >
              {loc}
            </button>
          ))}
        </div>
        <button onClick={prevStep} className="w-full text-stone-400 font-bold py-2">Volver al tipo de imagen</button>
      </div>
    </div>
  );

  // Step 4: CONTEXT / STYLE
  const renderStep4 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      {stepIndicator(4)}
      <div className="space-y-6">
        <h2 className="text-3xl font-bold text-black font-serif">4. Detalles de Estilo</h2>
        <div className="space-y-6">
          <div className="space-y-3">
            <label className="text-xs font-black text-stone-400 uppercase tracking-widest">Formato de Salida</label>
            <div className="grid grid-cols-4 gap-2">
              {['1:1', '4:5', '9:16', '16:9'].map(r => (
                <button key={r} onClick={() => setRatio(r as AspectRatio)} className={`py-4 rounded-xl border-2 font-black text-xs transition-all ${ratio === r ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100'}`}>{r}</button>
              ))}
            </div>
          </div>
          <div className="space-y-3">
            <label className="text-xs font-black text-stone-400 uppercase tracking-widest">Ambiente y Luz</label>
            <textarea value={state.contextText} onChange={(e) => setState(prev => ({ ...prev, contextText: e.target.value }))} className="w-full px-5 py-4 rounded-2xl border-2 border-stone-100 bg-white text-black placeholder-stone-300 outline-none h-32 font-medium focus:border-stone-300 transition-all shadow-sm" placeholder="Ej: Luz de atardecer, atmósfera cálida y acogedora, estilo minimalista..." />
          </div>
        </div>
        <div className="flex gap-4">
           <button onClick={prevStep} className="flex-1 py-5 rounded-2xl border-2 border-stone-200 font-bold">Atrás</button>
           <button disabled={loading} onClick={startConceptGeneration} className="flex-[2] py-5 bg-black text-white rounded-2xl font-bold shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3">
            {loading && <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />}
            Generar Propuestas
          </button>
        </div>
      </div>
    </div>
  );

  // Step 5: PROPOSALS
  const renderStep5 = () => (
    <div className="space-y-8 animate-in fade-in scale-95 duration-500">
      {stepIndicator(5)}
      <h2 className="text-2xl font-serif font-bold text-black text-center">Propuestas de Dirección de Arte</h2>
      <div className="space-y-4">
        {state.concepts.map((concept, idx) => (
          <div key={idx} className={`bg-white border-2 p-6 rounded-3xl shadow-sm transition-all ${state.editingConceptIndex === idx ? 'border-black ring-2 ring-black/5' : 'border-stone-100 hover:border-black'}`}>
            {state.editingConceptIndex === idx ? (
              <div className="space-y-4">
                <textarea autoFocus value={editValue} onChange={(e) => setEditValue(e.target.value)} className="w-full px-4 py-3 border-2 border-stone-100 rounded-xl text-stone-900 bg-stone-50 outline-none h-32 font-medium" />
                <div className="flex gap-2 justify-end">
                  <button onClick={() => setState(prev => ({ ...prev, editingConceptIndex: null }))} className="px-5 py-2 text-sm font-bold text-stone-500">Cancelar</button>
                  <button onClick={handleSaveEdit} className="bg-black text-white px-6 py-2 rounded-xl text-sm font-bold shadow-lg">Guardar</button>
                </div>
              </div>
            ) : (
              <div className="space-y-4">
                <p className="text-stone-900 font-medium italic text-lg leading-relaxed">"{concept}"</p>
                <div className="flex justify-between items-center pt-2">
                  <button onClick={() => { setEditValue(concept); setState(prev => ({ ...prev, editingConceptIndex: idx })); }} className="text-stone-400 hover:text-black font-bold text-xs uppercase tracking-widest">Ajustar Concepto</button>
                  <button disabled={loading} onClick={() => selectAndGenerate(idx)} className="bg-black text-white px-8 py-3 rounded-xl font-bold active:scale-95 transition-all text-sm shadow-xl shadow-black/5">Generar Imagen</button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
      <button onClick={prevStep} className="w-full text-stone-400 font-bold py-2">Volver a los detalles</button>
    </div>
  );

  // Step 6: RESULT
  const renderStep6 = () => (
    <div className="space-y-8 animate-in zoom-in-95">
      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 space-y-8">
          <div className="w-20 h-20 border-4 border-stone-100 border-t-black rounded-full animate-spin" />
          <h3 className="text-2xl font-bold text-black font-serif">Procesando Arte Final...</h3>
        </div>
      ) : error ? (
        <div className="py-24 text-center space-y-6">
          <p className="text-red-500 font-bold">{error}</p>
          <button onClick={() => selectAndGenerate(state.selectedConceptIndex!)} className="bg-black text-white px-8 py-3 rounded-xl font-bold">Reintentar</button>
        </div>
      ) : state.imageHistory[0] ? (
        <div className="space-y-8">
          <div className="rounded-[2.5rem] overflow-hidden border border-stone-100 shadow-2xl bg-white aspect-square relative">
            <img src={state.imageHistory[0]} alt="Final" className="w-full h-full object-cover" />
          </div>
          <div className="grid grid-cols-3 gap-3">
            <button onClick={() => selectAndGenerate(state.selectedConceptIndex!)} className={btnSecondary}>Regenerar</button>
            <button onClick={() => setState(p => ({ ...p, step: 5 }))} className={btnSecondary}>Alternativas</button>
            <button onClick={() => handleDownload(state.imageHistory[0])} className="py-4 rounded-xl bg-black text-white font-bold px-4 shadow-lg shadow-black/10">Descargar</button>
          </div>
          <div className="pt-6 border-t border-stone-100 space-y-4">
            <h4 className="text-sm font-black text-stone-900 uppercase tracking-widest">Ajustes Rápidos</h4>
            <div className="flex flex-wrap gap-2">
              {["Más contraste", "Luz cenital", "Estilo vintage", "Fondo oscuro"].map(s => (
                <button key={s} onClick={() => handleAdjustment(s)} className="px-4 py-2 rounded-full border border-stone-300 text-xs font-bold text-stone-900 bg-white hover:border-black">{s}</button>
              ))}
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );

  return (
    <div className="max-w-xl mx-auto pb-20">
      {state.step === 1 && renderStep1()}
      {state.step === 2 && renderStep2()}
      {state.step === 3 && renderStep3()}
      {state.step === 4 && renderStep4()}
      {state.step === 5 && renderStep5()}
      {state.step === 6 && renderStep6()}
    </div>
  );
};

export default CreativeFunnel;
